  sunny: '☀️',
  clear: '☀️',
  cloudy: '☁️',
  'partly cloudy': '⛅',
  rainy: '🌧️',
  rain: '🌧️',
  snow: '❄️',
  storm: '⛈️',
  thunderstorm: '⛈️',
  windy: '💨',
};

