import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  const currentIcon = useMemo(() => {
    const c = condition.toLowerCase().trim();
    if (c === 'sunny' || c === 'clear') return '☀️';
    if (c === 'partly cloudy') return '⛅';
    if (c === 'cloudy') return '☁️';
    if (c === 'rain' || c === 'rainy') return '🌧️';
    if (c === 'snow') return '❄️';
    if (c === 'storm') return '⛈️';
    return '🌤️';
  }, [condition]);

  const displayUnit = useMemo(() => {
    const u = unit?.toLowerCase().trim();
    if (u === 'f' || u === 'fahrenheit') return '°F';
    return '°C';
  }, [unit]);

  return {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    forecast,
    displayUnit,
    currentIcon,
  };
}


