// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {
  const { elements } = props;

  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElementIds = useMemo(() => {
    const query = searchQuery.toLowerCase();
    if (!query) {
      return new Set(elements.map((e) => e.atomicNumber));
    }
    return new Set(
      elements
        .filter((e) => e.name.toLowerCase().includes(query) || e.symbol.toLowerCase().includes(query))
        .map((e) => e.atomicNumber)
    );
  }, [elements, searchQuery]);

  const categories = useMemo(() => {
    return Array.from(new Set(elements.map((e) => e.category)));
  }, [elements]);

  return {
    searchQuery,
    setSearchQuery,
    filteredElementIds,
    selectedElement,
    setSelectedElement,
    categories,
  };
}


