import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';

function getCategoryColor(category: string): string {
  const normalized = category.toLowerCase();
  if (normalized.includes('alkali metal')) return 'var(--ggui-color-error-100, #fee2e2)';
  if (normalized.includes('alkaline earth')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (normalized.includes('transition metal')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  if (normalized.includes('post-transition')) return 'var(--ggui-color-info-100, #cffafe)';
  if (normalized.includes('metalloid')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (normalized.includes('noble gas')) return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  if (normalized.includes('halogen')) return 'var(--ggui-color-primary-50, #f0f9ff)';
  if (normalized.includes('nonmetal') || normalized.includes('non-metal')) return 'var(--ggui-color-container, #ede9fe)';
  if (normalized.includes('lanthanide')) return 'var(--ggui-color-warning-50, #fffbeb)';
  if (normalized.includes('actinide')) return 'var(--ggui-color-error-50, #fef2f2)';
  return 'var(--ggui-color-surface, #fafafa)';
}

export function ElementCell({ element, onClick, isSelected, isDimmed }: ElementCellProps) {
  return (
    <Box
      background={getCategoryColor(element.category)}
      {...({
        onClick,
        style: {
          gridRow: element.row,
          gridColumn: element.col,
          position: 'relative',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          alignItems: 'center',
          aspectRatio: '1',
          minHeight: '60px',
          padding: 'var(--ggui-spacing-1, 4px)',
          border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          cursor: 'pointer',
          transition: 'all 0.2s ease',
          opacity: isDimmed ? 0.3 : 1,
          boxShadow: isSelected ? 'inset 0 0 0 2px var(--ggui-color-primary-500, #0ea5e9)' : undefined,
          transform: isSelected ? 'scale(1.05)' : 'none',
          zIndex: isSelected ? 1 : 'auto',
        }
      } as any)}
    >
      <div style={{ position: 'absolute', top: '2px', left: '4px' }}>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          {element.atomicNumber}
        </Text>
      </div>
      <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
        {element.symbol}
      </Text>
    </Box>
  );
}


