import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function PeriodicGrid({ elements, filteredElementIds, onElementClick, selectedElementId }: PeriodicGridProps) {
  return (
    <Box
      style={{
        overflowX: 'auto',
        paddingBottom: 'var(--ggui-spacing-4, 16px)',
        width: '100%',
      }}
    >
      <Box
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(48px, 1fr))',
          gap: 'var(--ggui-spacing-1, 4px)',
          minWidth: '900px',
        }}
      >
        {elements.map((element) => (
          <ElementCell
            key={element.atomicNumber}
            element={element}
            isSelected={element.atomicNumber === selectedElementId}
            isDimmed={filteredElementIds.size > 0 && !filteredElementIds.has(element.atomicNumber)}
            onClick={() => onElementClick(element)}
          />
        ))}
      </Box>
    </Box>
  );
}


