import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

const CATEGORY_COLORS: Record<string, string> = {
  "diatomic nonmetal": "var(--ggui-color-success-200, #bbf7d0)",
  "noble gas": "var(--ggui-color-info-200, #bae6fd)",
  "alkali metal": "var(--ggui-color-error-200, #fecaca)",
  "alkaline earth metal": "var(--ggui-color-warning-200, #fde68a)",
  "metalloid": "var(--ggui-color-success-300, #86efac)",
  "polyatomic nonmetal": "var(--ggui-color-warning-300, #fcd34d)",
  "transition metal": "var(--ggui-color-primary-200, #bae6fd)",
  "post-transition metal": "var(--ggui-color-primary-300, #7dd3fc)",
  "lanthanide": "var(--ggui-color-info-300, #7dd3fc)",
  "actinide": "var(--ggui-color-error-300, #fca5a5)"
};

export function Legend(props: LegendProps) {
  const { categories } = props;

  return (
    <Box margin="var(--ggui-spacing-6, 24px) 0 0 0">
      <Stack direction="horizontal" wrap justify="center" gap="var(--ggui-spacing-4, 16px)">
        {categories.map((category) => {
          const color = CATEGORY_COLORS[category.toLowerCase()] || "var(--ggui-color-surfaceVariant, #f4f4f5)";
          const label = category
            .split(' ')
            .map(w => w.charAt(0).toUpperCase() + w.slice(1))
            .join(' ');

          return (
            <Stack key={category} direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
              <Box
                background={color}
                borderRadius="var(--ggui-spacing-1, 4px)"
              >
                <div style={{ width: '16px', height: '16px', border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'inherit' }} />
              </Box>
              <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                {label}
              </Text>
            </Stack>
          );
        })}
      </Stack>
    </Box>
  );
}


