// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}

export function useComponent(props: Props): HookReturn {
  const { initialProfile, onComplete } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<CompleteProfile>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? '',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? false,
    theme: initialProfile?.theme ?? 'light',
  });

  const totalSteps = 3;

  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^\S+@\S+\.\S+$/;
      return !formData.name || !formData.avatar || !emailRegex.test(formData.email);
    }
    if (currentStep === 2) {
      return !formData.role;
    }
    return false;
  }, [currentStep, formData]);

  const handleNext = useCallback(() => {
    if (!isNextDisabled && currentStep < totalSteps) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [isNextDisabled, currentStep, totalSteps]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const handleUpdateField = useCallback(<K extends keyof CompleteProfile>(field: K, value: CompleteProfile[K]) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  }, []);

  const handleSubmit = useCallback(() => {
    if (onComplete) {
      onComplete(formData);
    }
  }, [onComplete, formData]);

  return {
    currentStep,
    totalSteps,
    formData,
    isNextDisabled,
    handleNext,
    handleBack,
    handleUpdateField,
    handleSubmit,
  };
}


